import React, {useState} from "react";
import type {IKitsInputPassword} from "@lmb-it/kitsconcerto-types";
import KitsContainer from "../../helpers/FormContainer";
import {useSeparator} from "../../../factory";
import {Input, InputField, InputSlot} from "@lmb-it/kitsconcertomobile";
import Addons from "../../helpers/Addons";
import {useFormInputController} from "../../helpers/useFormInputController";
import Strengthen from "./Strengthen";
import {useComponentDefaults, useFocusStyles, useResolvedStyle} from "@lmb-it/kitsconcerto/hooks";
import {useFormFieldKeyboardNav} from "../../../hooks/useFormFieldKeyboardNav";
import {mergeRefs} from "../../../utils/mergeRefs";
import { Icon } from "../../../";

const KitsInputPassword = ({ref, ...rawProps}: IKitsInputPassword) => {
    const { mergedProps: props, themeStyle, elementStyles } = useComponentDefaults('InputPassword', rawProps, 'Input');
    const resolvedThemeStyle = useResolvedStyle(themeStyle);
    const resolvedRootStyle = useResolvedStyle(elementStyles?.root || {});
    const {
        id, label, helperText, errors, invalid, required, hideError,
        leftAddon, rightAddon, isFloatedLabel, disabled,
        promptLabel, weakLabel, mediumLabel, strongLabel, header, footer,
        feedback, toggleEye, showStrengthProgress,
        value, defaultValue, onChange, schema,
        eyeIcon, eyeSlashIcon,
        inputSize, ...rest
    } = props;

    const {inputRef, navProps} = useFormFieldKeyboardNav(id);

    const { nativeProps } = useSeparator<any>(rest);
    const { value: internal, emitChange } = useFormInputController<string>({
        value,
        defaultValue,
        onChange,
    });

    const [secure, setSecure] = useState(true);
    const toggleSecure = () => setSecure(!secure);

    const [isFocused, setFocused] = useState(false);
    const rootStyle = resolvedRootStyle && Object.keys(resolvedRootStyle).length > 0 ? resolvedRootStyle : resolvedThemeStyle;
    const focusResolvedStyle = useFocusStyles(rootStyle, isFocused);

    return (
        <KitsContainer
            id={id}
            helperText={helperText}
            isFloatedLabel={isFloatedLabel}
            hideError={hideError}
            required={required}
            leftAddon={leftAddon}
            rightAddon={rightAddon}
            errors={errors}
            invalid={invalid}
            label={label}
            disabled={disabled}
            inputSize={inputSize}
            elementStyles={elementStyles}
        >
            <Input
                {...(rest as any)}
                isDisabled={!!disabled}
                isInvalid={!!invalid}
                style={{width: "100%", ...focusResolvedStyle}}
            >
                <InputField
                    ref={mergeRefs(inputRef, ref)}
                    value={internal ?? ''}
                    onChangeText={(txt) => emitChange(txt)}
                    secureTextEntry={secure}
                    editable={!disabled}
                    placeholder={promptLabel}
                    onFocus={(e: any) => {
                        setFocused(true);
                        (rest as any)?.onFocus?.(e);
                    }}
                    onBlur={(e: any) => {
                        setFocused(false);
                        (rest as any)?.onBlur?.(e);
                    }}
                    {...navProps}
                />
                {toggleEye && (
                    <InputSlot onPress={toggleSecure} style={{paddingHorizontal: 12}}>
                        {secure
                            ? (eyeIcon ?? <Icon name={'eye'} />)
                            : (eyeSlashIcon ?? <Icon name={'eye-slash'} />)
                        }
                    </InputSlot>
                )}
            </Input>

            {showStrengthProgress && schema && (
                <Strengthen
                    value={internal ?? ''}
                    show={false}
                    schema={schema as any}
                />
            )}
        </KitsContainer>
    );
};

export default KitsInputPassword;
